import sys, platform
arch = platform.machine().lower()
os_name = sys.platform
if os_name == 'win32':
    os_key = 'windows'
elif os_name == 'darwin':
    os_key = 'darwin'
else:
    os_key = 'linux'
if 'aarch64' in arch or 'arm64' in arch:
    arch_key = 'arm64'
elif 'armv' in arch or arch == 'arm':
    arch_key = 'arm'
elif '64' in arch or 'x86_64' in arch or 'amd64' in arch:
    arch_key = 'amd64'
else:
    arch_key = 'i386'
return f"{os_key}_{arch_key}"
